div.p:
Call Sequence & Memory Deallocation Strategy
Standards: POSIX Thread Safety, Manual Heap Management, Memory Barriers
| {near: top-center}

Caller: "Caller Thread\n(Context)" {
shape: person
style.fill: "#E1F5FE"
}
MemoryPool: "MemoryPool Manager\n(pool_t *pool)" {
style.fill: "#F3E5F5"
style.stroke-width: 2
style.double-border: true
}
ChunkRegistry: "Chunk Linked List\n(pool->chunks)" {
style.fill: "#FFF3E0"
style.stroke-dash: 3
}
Bitmap: "Allocation Bitmap\n(pool->bitmap)" {
style.fill: "#E0F2F1"
}
SystemHeap: "System Heap\n(libc::free)" {
style.fill: "#E8F5E9"
style.stroke: "#2E7D32"
style.stroke-width: 3
}

MemoryPool.t_init: {
MemoryPool -> MemoryPool: "Atomic check: if (pool == NULL) return;"
MemoryPool -> MemoryPool: "pthread_mutex_lock(&pool->lock)"
MemoryPool."STATE TRANSITION:\n[POOL_ACTIVE] -> [POOL_TERMINATING]\n(0x01 -> 0x03)" {
style.font-color: red
style.bold: true
}
}

pre.code:
Leak_Warning_Block: {
  MemoryPool -> MemoryPool: "LOG_WARN: Detected %zu active leaks"

  Bitmap_Audit: {
    MemoryPool -> Bitmap: "audit_remaining_bits(pool->bitmap_size)"
    Bitmap -> MemoryPool: "uint64_t[] indices"
    MemoryPool -> MemoryPool: "Trace: 0x%016X leaked (offset: %d)"
  }
}

Cleanup_Loop: {
  ChunkRegistry -> MemoryPool: "next_chunk = current->next"

  # Step 1: Free User Data segment
  MemoryPool -> SystemHeap: "free(current->data_ptr)" {
    style.stroke: red
    style.animated: true
    tooltip: "Freeing the actual memory returned to user (Heap Arena Reclamation)"
  }
  SystemHeap --> MemoryPool: "ACK (Status: 0)"

  # Step 2: Free the Metadata node
  MemoryPool -> SystemHeap: "free(current)" {
    style.stroke: "#BF360C"
    style.animated: true
    tooltip: "Freeing the internal chunk_t struct metadata"
  }
  SystemHeap --> MemoryPool: "ACK (Status: 0)"

  MemoryPool -> MemoryPool: "current = next_chunk"
}

ChunkRegistry -> MemoryPool: "return NULL (End of Chain Walk)"

div.p:
MemoryPool.t_final: {
MemoryPool -> MemoryPool: "memset(pool, 0, sizeof(pool_t))" {
tooltip: "Mitigate Use-After-Free/Dangling Pointers in debug builds"
}
MemoryPool -> MemoryPool: "VALGRIND_DESTROY_MEMPOOL(pool)"
}

ul.li:
state: uint8_t (Offset 0x38)
| {
near: pool_destroy_sequence
style.stroke: orange
style.fill: "#FFFDE7"
}
